INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0687', 'The Optimizer Explosion', '3d-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'You are training a 30B parameter model on a single 80 GB H100. The FP16 weights occupy 60 GB, which fits comfortably. Optimizer is Adam with mixed-precision FP16 weights and an FP32 master copy. The system OOMs on the very first optimizer step. Identify the hidden memory tax and propose a software fix that does not change the model architecture.', 'Why does Adam mixed-precision training of a 30B model OOM on an 80 GB H100, and which sharding strategy fixes it?', '"60 GB fits in 80 GB, so the batch size must be too large." Batch size matters, but even with batch size 1, this system OOMs — the hidden cost is the optimizer, not the data.', 'The system OOMs because of the **Optimizer State**. Adam stores two additional tensors per parameter (first and second moments), plus master weights, all in FP32. ZeRO (Zero Redundancy Optimizer) or FSDP is the fix. Instead of replicating the full optimizer state on every GPU, shard it across all workers. ZeRO Stage 3 shards weights, gradients, and optimizer states, reducing per-GPU memory from 480 GB to ~120 GB across 4 GPUs.', 'A 30B parameter model''s FP16 weights require 30B * 2 bytes = 60GB, seemingly fitting an 80GB H100. However, training requires gradients (FP16, 60GB) and Adam optimizer states: FP32 master weights (120GB), FP32 momentum (120GB), and FP32 variance (120GB). Total memory needed = 60 + 60 + 120 + 120 + 120 = 480GB per GPU! The hidden Adam memory tax causes an instant OOM.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0687.yaml', '0a84e54a868662c834da6f799eeecf60e100866d24c8e2c5cdfb81e5a777c43d', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0823', 'The Gradient AllReduce Time', '3d-parallelism', 'cloud', 'L1', 'recall', 'parallelism', 'remember', 'training', 'published', 'You are running data-parallel training of a 7B model across 8 H100 GPUs in a single node connected via NVLink 4.0 (900 GB/s bidirectional). Gradients are in FP32. How long does the AllReduce synchronization take?', 'How long does the AllReduce synchronization take?', 'Dividing by the 900 GB/s bidirectional aggregate instead of the 450 GB/s unidirectional bandwidth — ring AllReduce is bottlenecked by the slowest unidirectional lane. Other common errors are using FP16 gradient size instead of FP32 or forgetting the 2*(N-1)/N ring factor.', 'About 109 ms. Gradient size = 7B * 4 bytes (FP32) = 28 GB. Ring AllReduce sends 2*(N-1)/N * data = 2*(7/8)*28 = 49 GB along the ring. The ring is bottlenecked by the *unidirectional* NVLink lane (450 GB/s for NVLink 4.0, since the 900 GB/s figure is bidirectional aggregate). Time = 49 / 450 ≈ 109 ms.', 'Gradients = 7B * 4 bytes (FP32) = 28 GB. Ring factor = 2*(8-1)/8 = 1.75. Bus traffic = 1.75 * 28 = 49 GB. Unidirectional NVLink 4.0 = 450 GB/s. Time = 49 / 450 ≈ 0.109 s ≈ 109 ms.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0823.yaml', 'be274bb8b0f0432604adaddd315ce6c9e657b9232acb0a315b9f32733dd3cbac', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-0899', 'Evaluating Parallelism Mapping Across the Bandwidth Taper', 'data-parallelism', 'cloud', 'L5', 'evaluation', 'parallelism', 'evaluate', 'training', 'published', 'Your team is architecting the distributed training topology for a 175B parameter LLM on a cluster of NVIDIA H100 nodes (8 GPUs per node). The hardware features a severe bandwidth taper: 900 GB/s intra-node via NVLink, and 50 GB/s (400 Gbps) inter-node via InfiniBand. A junior engineer proposes spanning Tensor Parallelism (TP) across multiple nodes to maximize memory pooling, while keeping Pipeline Parallelism (PP) contained within individual nodes to reduce pipeline bubbles. Evaluate this proposal and justify a mathematically sound topology.', 'Should tensor parallelism span multiple H100 nodes here, or how should TP, PP, and DP be mapped across the cluster?', 'Failing to quantify the communication intensity of TP versus PP, and ignoring the 18x bandwidth taper, leading to a topology where the highest-volume, blocking communications are forced over the slowest interconnect.', 'Reject the proposal. TP requires blocking All-Reduce operations for every layer, which will bottleneck on the 50 GB/s InfiniBand. PP only communicates activations at stage boundaries. The optimal topology maps TP strictly within the node to leverage the 900 GB/s NVLink, and maps PP and Data Parallelism (DP) across nodes.', 'Bandwidth taper ratio (unidirectional, the right number for ring/collective AllReduce): NVLink 4.0 (450 GB/s unidirectional, of the 900 GB/s bidirectional aggregate) / InfiniBand NDR (~25 GB/s unidirectional, of the 400 Gbps line rate) = 18x. For hidden dim 12,288, seq length 2,048, batch 4, a single TP AllReduce moves ~400 MB per layer. Over InfiniBand: 400 MB / 25 GB/s ≈ 16 ms per layer. Over NVLink: 400 MB / 450 GB/s ≈ 0.88 ms. Across 96 layers, forcing TP across nodes adds ~1.5 s of blocking overhead per step, ruining utilization.', 'imported', '2026-03-23T21:02:34.615108', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-0899.yaml', 'b2cf3e8b796e4139bb965f2030204d5c88510b889c2b1145f910b4a825051083', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1059', 'NCCL AllReduce vs Backward Compute Overlap on a 4-GPU T4 Box', 'data-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'You are training a small classification model on 4x T4 GPUs (PCIe Gen3 x16, ~12 GB/s per link, no NVLink, NCCL over PCIe). Per-step backward compute = 90 ms; the gradient AllReduce moves a 2 GB FP32 gradient over a logical PCIe ring. You can either run AllReduce in a separate NCCL stream with bucketed overlap (bucket size 64 MB, AllReduce kicked off as each bucket completes during backward) or run a single AllReduce after backward finishes. Compute total step time under each approach and identify the point at which doubling the bucket size stops helping.', 'On 4x T4s with no NVLink and a 2 GB FP32 gradient over PCIe, what does bucketed AllReduce overlap save versus a post-backward single AllReduce, and where do bucket-size returns diminish?', 'Computing AllReduce time as `payload / bandwidth = 2 GB / 12 GB/s = 167 ms` and forgetting the 2*(N-1)/N ring factor (under-counts bus traffic by ~50% for N=4). Or treating bucket size as monotonically beneficial — past the optimum, the last bucket''''s exposed time grows because backward finishes before the bucket fills.', 'Single post-backward AllReduce: bus traffic = 2*(3/4) * 2 GB = 3 GB on a logical PCIe ring at ~12 GB/s → 250 ms. Step time = 90 ms backward + 250 ms comm = 340 ms (no overlap). Bucketed AllReduce (64 MB buckets): backward completes one bucket every ~3 ms, AllReduce of one 64 MB bucket = 2*(3/4) * 64 MB / 12 GB/s ≈ 8 ms. The first ~25 buckets'' AllReduces overlap with the rest of backward; only the last bucket''s 8 ms is fully exposed. Step time ≈ 90 ms + ~30-50 ms exposed tail ≈ ~125-140 ms (a 2.4-2.7x speedup over no-overlap). Doubling bucket size beyond 256 MB stops helping because each AllReduce launch latency (~50 µs) is amortized at 64-256 MB; past 256 MB the bucket *fills* slower than its AllReduce runs, so the exposed tail grows again.', 'Gradient = 2 GB FP32. Ring AllReduce traffic = 2*(3/4) * 2 GB = 3 GB. PCIe ring effective bandwidth ≈ 12 GB/s. Single AllReduce = 3 / 12 = 250 ms. Bucketed (64 MB): per-bucket AllReduce = 2*(3/4) * 64 MB / 12 GB/s ≈ 8 ms; backward fills one bucket every ~3 ms; only the last AllReduce''s ~8 ms is exposed. Step ≈ 90 + ~30-50 ms ≈ 125-140 ms.', 'imported', '2026-03-23T21:38:09.294410', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1059.yaml', 'fc1aceb76aae19858dcbb24d5127518c5b0faf63f43ee61d403bc6768da1f567', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1088', 'Diagnosing DDP Network Bottlenecks', 'data-parallelism', 'cloud', 'L4', 'diagnosis', 'parallelism', 'analyze', 'training', 'published', 'You are training a 2-billion parameter model using PyTorch Distributed Data Parallel (DDP) across 4 nodes (8x A100 80GB GPUs per node), connected via 100 Gbps Ethernet inter-node and NVLink intra-node. The framework uses hierarchical AllReduce — intra-node reduce-scatter on NVLink, then inter-node AllReduce of the per-node-reduced tensor across the 4 nodes, then intra-node AllGather. Single-node GPU utilization is 98%, but drops to 42% when scaling to 4 nodes. Profiling shows GPUs are stalling during the inter-node step of the backward-pass synchronization. Diagnose the root cause and propose a software-only fix that does not change the model architecture.', 'Under hierarchical AllReduce, why does utilization drop from 98% to 42% across 4 nodes, and what software-only fix improves scaling?', 'Computing AllReduce traffic as 2*(N-1)/N * size with N=32 (the flat-rank count) instead of N=4 (the inter-node ring). Hierarchical AllReduce''s bottleneck is the inter-node reduction over 100 Gbps, not a flat 32-way ring on the slowest link. Candidates also misdiagnose as a dataloader bottleneck or jump to Tensor Parallelism without measuring the comm-to-compute ratio.', 'The inter-node step of hierarchical AllReduce is the binding constraint. Intra-node reduce-scatter on NVLink shrinks the 4 GB FP16 gradient down to a 4 GB / 8 = 0.5 GB per-rank shard, but each node must then AllReduce a 4 GB tensor across the 4 nodes over 100 Gbps Ethernet. Inter-node AllReduce moves 2*(N-1)/N * 4 GB = 2*(3/4)*4 = 6 GB at 12.5 GB/s, taking 0.48 s versus 0.2 s of compute — yielding utilization of 0.2 / (0.2 + 0.48) = 29.4%. Use gradient accumulation (e.g., 4 micro-steps via `no_sync()`) so compute per AllReduce climbs to 0.8 s, lifting serial utilization to 62.5%. Combined with bucketed AllReduce that overlaps the inter-node step with later parts of backward, achievable utilization climbs into the 80-90% range.', '2B FP16 params = 4 GB gradients per rank. Hierarchical AllReduce intra-node step on NVLink is far below 1 ms and is not the bottleneck. Inter-node AllReduce across N=4 nodes transfers 2*(N-1)/N * 4 GB = 6 GB on the 100 Gbps (12.5 GB/s) Ethernet ring → 0.48 s. Step time = 0.2 s compute + 0.48 s comm → utilization = 29.4%. Accumulate 4 micro-steps → compute = 0.8 s, utilization = 0.8 / 1.28 = 62.5%. With bucketed AllReduce overlapping inter-node comm against later backward kernels, exposed comm drops to roughly 0.05-0.1 s and utilization approaches 80-90%.', 'imported', '2026-03-23T21:44:55.607713', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1088.yaml', '0ae01b93fe28fb429c7f24fb5b49db6188177ae391cce5e329b9b9aead7a6903', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1578', 'Diagnosing MoE Routing and OOM Bottlenecks', 'mixture-of-experts', 'cloud', 'L4', 'diagnosis', 'parallelism', 'analyze', 'both', 'published', 'You are serving an 8x7B Mixture of Experts (MoE) model (56B total parameters, 14B active per token) across an 8x A100 80GB node using Expert Parallelism (1 expert per GPU). The total model weights are ~112GB in FP16, easily fitting in the 640GB cluster memory. However, at a batch size of 256 and sequence length of 2048, you experience intermittent Out-of-Memory (OOM) crashes on specific GPUs and massive tail latency spikes. Standard metrics show average cluster GPU utilization is below 40%. Diagnose the root cause of the OOM crashes and the latency degradation.', 'Why do specific GPUs OOM and tail latency spike under expert parallelism, and how should you fix the 8x7B MoE serving path?', 'Candidates often blame the total KV cache size or general all-to-all communication overhead, missing that Expert Parallelism makes individual GPU memory and compute dependent on dynamic routing distributions. They often suggest global batch size reduction instead of addressing expert imbalance.', 'The root cause is severe load imbalance (token skew) where the router sends a disproportionate number of tokens to a single expert. This causes the target GPU to exceed its 80GB VRAM limit due to localized activation and KV cache spikes, and serializes compute, causing tail latency. The fix is to implement a strict expert capacity limit (token dropping/overflow to other experts) and combine Expert Parallelism with Tensor Parallelism to distribute the hot expert''s memory footprint.', 'Total VRAM: 8x80GB = 640GB. Model: 56B * 2B = 112GB (14GB/GPU). Remaining VRAM/GPU: 66 GB. Per-token activation+KV cost for the 8x7B MoE layer ≈ 0.13 MB/token (hidden=4096, seq=2048, BF16, with KV cache and FFN intermediates). Balanced load: 524k tokens / 8 = 65.5k tokens on each GPU → ~8.5 GB activation+KV per GPU. Skewed routing (95% of tokens to Expert 2): GPU 2 processes 498k tokens → 64.7 GB of activation+KV. Combined with the 14 GB expert weights, GPU 2 needs 78.7 GB *just for the MoE block* — plus router state, attention state, and PyTorch workspace overhead (typically 8-15 GB), pushing total well past the 80 GB ceiling and OOMing GPU 2 while GPUs 0, 1, 3-7 sit at ~22 GB each.', 'imported', '2026-03-23T23:39:17.456643', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1578.yaml', 'dc0ff20082290076b9776765a336fb9355f4f48d09ede5a3c38b2ccec5bfbfbc', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1609', 'Calculating Minimum Model Parallelism Degree', 'model-tensor-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'As a theoretical sizing exercise (not a production recommendation), calculate the minimum tensor-parallel degree N that would let a 30-billion parameter transformer fit its training state on 40 GB A100s if we deliberately disabled ZeRO-style optimizer-state partitioning, FSDP, and pipeline parallelism, and forced the entire mixed-precision Adam state to live on one tensor-parallel group. Mixed-precision FP16 Adam keeps FP16 weights, FP16 gradients, and FP32 master weights, momentum, and variance. Reserve 8 GB per GPU for activations and workspace. (Production teams use FSDP/ZeRO; this exercise isolates the sizing math that motivates them.)', 'Theoretical: what minimum tensor-parallel degree fits the 30B mixed-precision Adam training state on 40GB A100s if ZeRO/FSDP and PP are disabled?', 'Calculating memory requirements based only on the 16-bit model weights (which would be 60GB total, incorrectly implying just 2 GPUs), completely ignoring the 14 bytes/param overhead of gradients, master weights, and Adam optimizer states.', 'In standard mixed-precision training, each parameter requires 16 bytes of memory (2 bytes for FP16 weights, 2 bytes for FP16 gradients, 4 bytes for FP32 master weights, 4 bytes for FP32 momentum, and 4 bytes for FP32 variance). A 30B parameter model thus requires 480GB of memory. With 32GB of usable memory per 40GB GPU, 15 GPUs are mathematically required. To maintain symmetrical division across attention heads and efficient communication topologies, the realistic minimum Model Parallelism degree is 16.', 'State per param = 2 (FP16 W) + 2 (FP16 G) + 4 (FP32 W) + 4 (FP32 M) + 4 (FP32 V) = 16 bytes.
Total Model State = 30e9 * 16 bytes = 480 GB.
Usable GPU Memory = 40 GB - 8 GB (activations) = 32 GB.
Minimum GPUs = 480 GB / 32 GB = 15 GPUs.
Nearest hardware-friendly power of 2 = 16.', 'imported', '2026-03-23T23:48:10.749702', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1609.yaml', 'b0aa8cd8de63b2c7b8e6b5cd5457cc76338c0f4a39407797a7f73188f284f882', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1748', 'Data-Parallel Process Group Misalignment in 3D Training', 'data-parallelism', 'cloud', 'L4', 'diagnosis', 'parallelism', 'analyze', 'training', 'published', 'You are debugging a 175B parameter model training job on a 1024-GPU A100 cluster (128 nodes, 8 GPUs/node) using 3D parallelism (TP=8, PP=16, DP=8). The DP gradient AllReduce at the end of each backward pass should run only over the 8 ranks that share the same TP/PP coordinates (a logical 8-way ring on InfiniBand HDR at ~25 GB/s unidirectional). Instead, profiling shows the DP AllReduce time is 10x higher than expected and that *every* rank in the world (1024 GPUs) participates in the collective. Throughput has degraded by 60%. Root-cause the bottleneck and propose the process-group fix.', 'Why is the DP AllReduce running over all 1024 ranks instead of the 8-rank DP group, and what process-group fix is needed?', 'Assuming `torch.distributed.all_reduce` automatically infers the right subgroup from the tensor''s parallelism dimension. NCCL has no notion of TP/PP/DP coordinates — group membership is fully explicit, and a missing `group=` argument silently routes the collective to the world group.', 'Diagnose that the DP AllReduce call is missing its `group=` argument and defaulting to `dist.group.WORLD`. Fix it by explicitly passing the initialized Data Parallel process group (e.g., `group=dp_group`) so NCCL restricts the gradient sync to the 8 ranks that share the same (TP coord, PP coord). After the fix, the AllReduce runs over the intended 8-way DP ring at ~25 GB/s unidirectional IB, and AllReduce volume drops by the ratio of world ranks to DP ranks (1024/8 = 128x reduction in bus traffic for the same gradient shard).', 'DP gradient shard for a 175B model with TP=8, PP=16 = 175B / (TP*PP) ≈ 1.37B params * 2 bytes (BF16) = 2.74 GB per DP rank. Correct DP AllReduce on the 8-rank group over IB HDR (~25 GB/s unidirectional) — 2*(7/8) * 2.74 GB / 25 GB/s ≈ 192 ms. Wrong AllReduce on the full 1024-rank world over the same IB fabric — 2*(1023/1024) * 2.74 GB / 25 GB/s ≈ 219 ms *per ring hop*, but the 1024-rank ring traverses many more inter-node hops and contends with TP/PP traffic, blowing the 192 ms target by ~12x.', 'imported', '2026-03-24T00:32:28.917323', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1748.yaml', '6b76c2dd2e6dd69494b693ce0cc5eab4d60f4bc242cf3e73ebb6238e926a35a8', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1751', 'Counting Data-Parallel Process Groups in a 3D Layout', 'data-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'A 175B-parameter LLM trains on 512 A100 GPUs (64 nodes, 8 GPUs per node) under 3D parallelism with TP=8, PP=8, DP=8. The team needs to know exactly how many *DP* NCCL process groups must be initialized and which 8 ranks belong to each, so that the per-step gradient AllReduce runs only over the correct ranks and does not default to the world group. Walk through the calculation and identify which IB links each DP group''s ring traffic actually traverses.', 'Under TP=8, PP=8, DP=8 on 512 GPUs, how many DP process groups must be initialized, and which 8 ranks belong to each — and which links does the DP AllReduce traverse?', 'Computing the *total* number of process groups (192 = 64+64+64) when the question asked for DP groups only. Or — worse — initializing only one global DP group and relying on `dist.group.WORLD`, which silently routes the 8-way DP collective over all 512 ranks and stalls every step.', 'There are TP * PP = 64 DP process groups, one per (TP coord, PP coord) pair. Each DP group contains 8 ranks — exactly the 8 ranks that share the same (TP coord, PP coord) and differ only in their DP coord. Concretely, a DP group is the set of ranks at positions (dp_i, pp_j, tp_k) for fixed (j, k) and dp_i ∈ {0..7}. Because DP varies across nodes (TP fits inside one node''s NVLink island, PP varies across nodes, DP also crosses node boundaries), the DP AllReduce traverses 7 IB HDR (200 Gbps) inter-node hops per ring, not the NVLink intra-node fabric. The gradient AllReduce is therefore bottlenecked by the IB ring''s ~25 GB/s unidirectional link, not by NVLink.', 'Total GPUs = DP(8) * PP(8) * TP(8) = 512. Number of DP groups = TP * PP = 8 * 8 = 64. Each DP group: 8 ranks, one per DP coordinate, all sharing the same (TP coord, PP coord). DP gradient shard size = 175B / (TP*PP) = 2.73B params * 2 bytes (BF16) = 5.47 GB. Ring AllReduce traffic on each 8-rank DP group = 2*(7/8) * 5.47 GB = 9.57 GB per rank. At IB HDR ~25 GB/s unidirectional: AllReduce ≈ 0.38 s.', 'imported', '2026-03-24T00:33:05.637630', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1751.yaml', 'c3e9e3f42d937951bcb095016a2549b990eba28d68d4397acb4c4aa179da607c', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-1840', 'LSTM Sequential Latency Bound on A100 GPUs', 'data-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'apply', 'training', 'published', 'You are optimizing an LSTM-based sequence-to-sequence model for real-time translation on an NVIDIA A100 GPU. The model uses a hidden size of 2048 and processes sequences of length 512. Profiling shows that a single LSTM cell state update (dominated by a 2048x2048 matrix multiplication) takes 5 microseconds on the A100. A junior engineer suggests increasing the batch size to 256 to fully saturate the GPU''s tensor cores and drastically reduce the end-to-end latency of processing a 512-token sequence. Calculate the theoretical minimum latency for a single sequence and evaluate the engineer''s claim.', 'What is the theoretical minimum latency for one 512-token LSTM sequence, and will increasing batch size to 256 reduce it?', 'Assuming that massive parallel compute capacity or increased batch size can parallelize operations across the time dimension of an LSTM, thereby reducing end-to-end sequence latency.', 'Batching increases throughput but cannot bypass the sequential dependency constraint where the hidden state h_t relies on h_{t-1}. The minimum latency is strictly bounded by the number of time steps multiplied by the computation time of a single step.', 'Time per step = 5 µs. Sequence length (N) = 512. Minimum sequence latency = N * 5 µs = 512 * 5 µs = 2560 µs = 2.56 ms. Batching to 256 improves overall sequences/sec (throughput) but the latency for processing any individual 512-token sequence remains bounded at 2.56 ms. The engineer is incorrect.', 'imported', '2026-03-24T00:54:35.078036', NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-1840.yaml', 'c6c6ed3aaa6b129927c4ffa6d16dfb04239bbdbbbc7ff5c5d6e050681d5ae2b8', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2701', 'Synchronous FSDP Straggler Mitigation at 256 GPUs', 'data-parallelism', 'cloud', 'L5', 'evaluation', 'parallelism', 'evaluate', 'training', 'published', 'A 256-GPU training job for a 7B LLM is running synchronous PyTorch FSDP (ZeRO-3 sharding) on H100 nodes connected with InfiniBand NDR. p50 step time is 720 ms, but p99 step time is 1.4 s — a 30% per-step straggler tail caused by intermittent ECC retries and one slow rack. The team must keep AdamW convergence intact for the 7B run. Evaluate three production options — (a) a pure synchronous FSDP run with no mitigation, (b) synchronous FSDP plus N+2 backup workers with infrastructure-level node remediation, and (c) bounded-staleness asynchronous FSDP with a one-step staleness window.', 'For 256-GPU synchronous FSDP training of a 7B LLM with a 30% straggler tail, which mitigation strategy preserves convergence with the smallest throughput cost?', 'Reaching for stale-gradient asynchronous schemes (SSP/ASP) at LLM scale. These were proposed for parameter-server CNN workloads on commodity Ethernet and have been deprecated for foundation-model training because Adam''s second-moment estimate amplifies stale-gradient noise — modern 256-GPU stacks use synchronous FSDP plus infrastructure remediation, not bounded-staleness training.', 'Choose (b), synchronous FSDP plus backup workers and node remediation. AdamW at 7B scale is sensitive to even one-step gradient staleness once the run is past warmup; option (c) risks the kind of silent loss-spike that has cost real teams entire runs. Option (a) lets the slowest rank dominate every collective, so step time stays at p99 = 1.4 s. With backup workers and a fast eviction policy that quarantines a rack as soon as its rank is consistently in the top quartile of step time, the AllReduce/ReduceScatter is run over a healthy 256-rank world while the stragglers are resharded to spares. Throughput recovers to roughly p50 = 720 ms with a 1-3% redundancy overhead versus the >40% gap between p50 and p99.', 'Pure synchronous (a): step = p99 = 1.4 s, throughput ratio = 1.0x (baseline waste). Backup workers (b): once a slow rack is quarantined, step → p50 = 720 ms; redundancy cost = (k_backup / 256) ≈ 1-3%. Effective throughput = 1.4 / 0.72 × (1 - 0.03) ≈ 1.88x over (a). Bounded-staleness async (c): throughput per step similar to (b) but expected loss-curve degradation of 5-15% extra steps to target loss for a 7B model — net wall-clock often *worse* and risks divergence under AdamW.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2701.yaml', '247808bf0d2844bb7b078b61b2a837831d3c8a2eaf8fd160550b1fd6c37f4cea', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2711', 'Data Parallelism Around an Expert-Parallel MoE Block', 'data-parallelism', 'cloud', 'L2', 'recall', 'parallelism', 'understand', 'training', 'published', 'An MoE Transformer has 64 experts placed 1-per-GPU across 64 H100s (expert parallel). The team wants to scale throughput by *also* applying data parallelism — replicating the full 64-GPU expert topology N times so the global batch grows by N. Explain what data parallelism *does* at this level given that expert parallelism already shards the experts, and what additional cost the outer DP introduces.', 'When DP wraps an already expert-parallel 64-GPU MoE block, what does the DP layer actually replicate, and what AllReduce cost does it add?', 'Believing that adding DP on top of expert parallelism doubles the all-to-all dispatch cost. The dispatch all-to-all is *intra-replica* and is unaffected by DP. What DP adds is a *separate* AllReduce on the gradient at the end of backward, sized to the per-replica parameter footprint — completely orthogonal to the dispatch step.', 'The DP layer replicates the entire expert-parallel mesh — each DP replica holds its own 64-GPU set of experts. The dense (non-expert) parts of the model (embeddings, attention, LayerNorms, the router) are also replicated across DP groups. After backward, the DP gradient AllReduce runs over the cross-replica group of identically-positioned ranks (one per replica), not over the expert dimension. So the DP collective synchronizes (a) the dense weight gradients across replicas and (b) one specific expert gradient across all replicas that hold a copy of that expert (which they all do — every replica has all 64 experts). Cost = one AllReduce of (dense + 1/64 * total expert params) per DP rank, sized to the active parameters per token, not the full sparse parameter count.', '8x7B MoE on 64 GPUs (1 expert/GPU): per-GPU params ≈ 7B (one expert) + ~1B dense = 8B. DP=4 outer replication ⇒ total fleet = 256 GPUs. DP gradient AllReduce per rank: 8B * 2 bytes (BF16) = 16 GB across the 4-way DP group; on IB NDR ~25 GB/s unidirectional, ring AllReduce = 2*(3/4) * 16 GB / 25 GB/s ≈ 0.96 s. The MoE all-to-all dispatch is a separate, intra-replica cost and does not scale with DP.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2711.yaml', '1b73843d0f499ba58f7d17214800e11827a27918110aaf0bca939e33d6812c77', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2799', 'Privacy-Preserving Cross-Tenant Data-Parallel Aggregation', 'data-parallelism', 'cloud', 'L6+', 'mastery', 'parallelism', 'create', 'training', 'published', 'Architect a privacy-preserving cross-tenant data-parallel training system for a 70B language model across three cloud regions, each with a pod of 64 H100 GPUs (NVLink intra-node 900 GB/s bidirectional, InfiniBand NDR 400 Gbps inter-node, 200 Gbps inter-region WAN). Tenants will not share raw gradients in plaintext. Design the per-step aggregation architecture so that (a) intra-pod ring AllReduce stays on the high-bandwidth fabric, (b) cross-region aggregation runs over secure multi-party-computation averaging without stalling the next step''s forward pass, and (c) the cross-region step''s communication cost is bounded so that it can be hidden behind the per-step backward pass.', 'How would you architect privacy-preserving 3-region data-parallel aggregation for a 70B model on 192 H100s with secure cross-region averaging?', 'Treating this as edge federated learning and reaching for LoRA + quantized adapters. The bottleneck here is cross-region WAN bandwidth and the unidirectional ring AllReduce factor on a bandwidth-tapered fabric, not device-RAM constraints. Another common error is running secure aggregation on the *full* 140 GB gradient over the 200 Gbps WAN — that takes 5.6 s per step and starves compute.', 'Use hierarchical AllReduce with a secure-aggregation outer step. Inside each pod, run a standard NCCL ring AllReduce on the FP16 gradient over NVLink/IB; this produces one 140 GB FP16 tensor per region. Compress the per-region tensor with PowerSGD (rank-8) to roughly 14 GB before cross-region transmission, then run a Bonawitz-style secret-shared additive aggregation across the three regional aggregators over the 200 Gbps WAN. Pipeline the cross-region step by issuing the secure-aggregation AllReduce immediately when the local pod finishes reduce-scatter, so the cross-region 14 GB / 25 GB/s ≈ 0.56 s overlaps with the next step''s ~0.7 s backward pass. Use bounded staleness of 1 step for the cross-region average so any straggler region does not block intra-pod progress.', '70B FP16 gradient = 140 GB per region. Intra-pod ring AllReduce over 64 H100s on IB NDR (effective ~40 GB/s unidirectional) transfers 2*(63/64)*140 GB ≈ 275 GB → ~6.9 s naive, ~0.9 s with NVLink-aware hierarchical reduce. Cross-region step — PowerSGD rank-8 compresses 140 GB to ~14 GB; secure aggregate over 200 Gbps (25 GB/s) WAN moves 2*(2/3)*14 GB = 18.6 GB → ~0.75 s. Backward pass for 70B on 64 H100s ≈ 0.7-0.8 s, so the cross-region step is hideable with one-step staleness.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2799.yaml', 'eecfc7990d47ea86cb16085d30483f2ff1e3fa242bcd8c0d58d8b1905c7e80c8', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-2807', 'Heterogeneous-Bandwidth Data-Parallel AllReduce Architecture', 'data-parallelism', 'cloud', 'L6+', 'mastery', 'parallelism', 'create', 'training', 'published', 'Architect a data-parallel AllReduce strategy for a 13B parameter model trained on 128 A100 80 GB GPUs distributed across 16 nodes. The cluster has heterogeneous interconnect — 8 of the 16 nodes share an InfiniBand HDR (200 Gbps) island, while the other 8 nodes are connected only via 100 Gbps Ethernet to the IB island via two gateway switches. Per-node intra-node fabric is NVLink 3.0 (600 GB/s bidirectional / 300 GB/s unidirectional). Design a DP-only synchronization strategy that respects this asymmetric topology and bounds the exposed AllReduce time so that it fits inside the 380 ms backward pass.', 'How would you architect data-parallel AllReduce on 128 A100s split between an InfiniBand HDR island and an Ethernet half so synchronization fits inside a 380 ms backward pass?', 'Treating the 128-GPU world as a flat ring AllReduce. A flat ring is bottlenecked by the slowest link (the 100 Gbps Ethernet), so total bus traffic = 2*(127/128) * 26 GB ≈ 51.6 GB at 12.5 GB/s ≈ 4.1 s — over 10x the backward pass. The fix is hierarchy and topology awareness, not gradient compression alone.', 'Use a topology-aware three-level hierarchical AllReduce instead of a flat 128-rank ring. Level 1: intra-node ring reduce-scatter on NVLink (sub-1 ms per node). Level 2: split the global AllReduce into two parallel sub-rings (one for the IB island and one for the Ethernet half) and bridge them via a single dedicated reduction over the 100 Gbps gateway link. Level 3: intra-node AllGather on NVLink. Pipeline this with bucketed AllReduce (32 MB buckets) so the slow gateway hop overlaps with the latter half of the backward pass. Also enable BF16 gradient communication to halve the payload from 52 GB to 26 GB so the gateway hop fits inside the 380 ms budget once overlapped.', 'Gradient = 13B * 2 bytes (BF16) = 26 GB. Flat ring on the 12.5 GB/s gateway: 51.6 GB / 12.5 ≈ 4.1 s. Two sub-rings + bridge hop: each sub-ring (8 nodes, ~25 GB/s unidirectional IB) moves 2*(7/8)*26 GB / 25 GB/s ≈ 1.8 s naive, ≈150 ms with NVLink-aware reduce-scatter inside each node. Gateway bridge hop moves 26 GB once at 12.5 GB/s ≈ 2.08 s un-overlapped; bucketed pipelining of 32 MB chunks cuts *exposed* gateway time to ≈ 200-300 ms once overlapped with backward. Total exposed AllReduce ≤ 380 ms.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-2807.yaml', '4c476cb8de5ad8216c65aa9656c1eab39b642d9febb32b3601757fd6bbcdca83', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3054', 'Pipeline Parallelism Bubble Overhead Comparison: GPipe vs PipeDream', 'pipeline-parallelism', 'cloud', 'L4', 'evaluation', 'parallelism', 'evaluate', 'training', 'published', 'You are comparing GPipe and PipeDream-Flush scheduling on a 4-stage H100 pipeline (80GB HBM3, 3.35TB/s) with micro-batch size m=16. GPipe uses a synchronous flush after each mini-batch, while PipeDream-Flush uses 1F1B ordering. Calculate bubble overhead for each and recommend the approach for a 32B parameter model training run.', 'For a 4-stage H100 pipeline with 16 micro-batches, what are the GPipe and PipeDream-Flush bubble overheads, and which should train a 32B model?', 'Students often forget that GPipe bubble fraction is (p-1)/(m+p-1) where p=stages, m=micro-batches, and conflate stage count with device count.', 'GPipe bubble fraction = (4-1)/(16+4-1) = 3/19 ≈ 15.8%. PipeDream-Flush with 1F1B achieves same bubble fraction but with O(p) memory footprint instead of O(m) activations stored. For 32B model across 4 H100s (each 80GB), PipeDream-Flush is preferred because storing 16 micro-batch activations in GPipe requires ~16x per-stage activation memory.', 'Bubble fraction (same for both schedules): (p-1)/(m + p-1) = 3/19 ≈ 15.8%. Per-stage parameter memory (32B model, 4 stages, FP16): 32B / 4 = 8B params * 2 bytes = 16 GB weights per stage; with FP16 grads + FP32 master/m/v under mixed-precision Adam, total state per stage ≈ 16 bytes * 8B = 128 GB — already over the 80 GB H100 even before activations, implying ZeRO/FSDP must shard the optimizer state across the data-parallel dimension. Assume that has been done so that per-stage non-activation state is ~24 GB. Activation budget per stage: 80 - 24 = 56 GB. Per-micro-batch activation (hidden 6144, seq 2048, batch per micro-batch 1, BF16 with checkpointing) ≈ 3.5 GB. GPipe peak activation memory = m * 3.5 GB = 56 GB at m=16 → just at the budget; small workspace fluctuation OOMs. PipeDream-Flush peak = p * 3.5 GB = 14 GB at p=4 — comfortable headroom, no OOM risk.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3054.yaml', 'a181618c86b9c620c184ef8d2b920d0ad08d2d130673f36a3f3588af5ecde12b', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3427', 'Choosing Micro-Batch Count for an 8-Stage A100 Pipeline', 'pipeline-parallelism', 'cloud', 'L3', 'analyze', 'parallelism', 'analyze', 'training', 'published', 'A 100B-parameter transformer is split into 8 pipeline stages on 8 A100 80 GB GPUs (312 TFLOPS FP16, 2.0 TB/s HBM, NVLink 600 GB/s bidirectional / 300 GB/s unidirectional). Per-stage forward+backward for one micro-batch is ~200 ms. Stage-to-stage activation transfer per micro-batch is 240 MB at NVLink speeds. The team''s compute budget is 1 hour per global step at most. Choose the micro-batch count m that brings bubble fraction below 10% while keeping the activation memory footprint of 1F1B inside the 80 GB HBM budget (weights + gradients + optimizer shard already consume 60 GB per stage).', 'For an 8-stage A100 1F1B pipeline with 200 ms stages and 60 GB of non-activation state per stage, what micro-batch count m brings bubble fraction below 10% without OOMing on activations?', 'Choosing m to maximize throughput without accounting for the O(k) activation memory in 1F1B (or worse, switching to GPipe whose O(m) activation memory OOMs at m=64). Another error is treating activation transfer as the bottleneck — at NVLink speeds 240 MB transfers in <1 ms, far below the 200 ms compute per stage.', 'Under 1F1B, peak activation memory is O(k) — at most k = 8 in-flight micro-batches of activations per stage. With 80 GB HBM and 60 GB consumed by weights+gradients+optimizer, the activation budget per stage is 20 GB, so per-micro-batch activation must stay under 20/8 = 2.5 GB. Sizing the micro-batch to hit ~2.5 GB of activations sets the per-stage compute time. To drive bubble below 10%, solve (k-1)/(m + k-1) ≤ 0.1 → m ≥ 9*(k-1) = 63. Choose m = 64 (round to power of 2). Bubble fraction = 7/71 ≈ 9.86%. Activation transfer time per micro-batch on NVLink: 240 MB / 300 GB/s ≈ 0.8 ms — negligible vs the 200 ms per-stage compute. Total step time = (m + k - 1) * 200 ms = 71 * 200 ms = 14.2 s, well inside the 1 h budget.', 'Bubble target: (k-1)/(m + k-1) ≤ 0.1 → m ≥ 63 → choose m = 64. Activation budget per stage = 80 - 60 = 20 GB; under 1F1B at most k = 8 in-flight activation tensors → per-micro-batch activation ≤ 2.5 GB. Step time = 71 * 200 ms = 14.2 s; bubble fraction = 9.86%; activation transfer cost = 0.8 ms / micro-batch on NVLink (negligible).', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3427.yaml', 'cd634b33d9147d2f97f216d50189314a77359009df0ed41026a88d9fbd24ff22', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3429', 'Pipeline Bubble on a Heterogeneous TPU v5e Stage Layout', 'pipeline-parallelism', 'cloud', 'L4', 'optimization', 'parallelism', 'analyze', 'training', 'published', 'A 500B-parameter LLM is split into 8 pipeline stages on 8 TPU v5e devices (16 GB HBM, 197 TFLOPS BF16, 1.6 TB/s HBM bandwidth, ICI inter-chip ~25 GB/s per axis). Stage compute times measured per micro-batch — stages 1-7 each 100 ms, stage 8 (LM head + softmax over a 256K vocab) 175 ms. The pipeline currently runs with 4 micro-batches per global step. Quantify the bubble fraction and the exposed throughput loss from the slowest stage, and identify the smallest schedule change that closes the gap to within 10%.', 'For an 8-stage TPU v5e pipeline with a 175 ms stage-8 vs 100 ms stage 1-7 and m=4 micro-batches, what is the bubble fraction and what schedule change brings utilization to within 10% of ideal?', 'Increasing m alone without rebalancing the stages. Bubble fraction shrinks but every micro-batch still pays the 175 ms stage-8 cost — pipeline rate is bounded by the slowest stage, not by the bubble.', 'Bubble fraction at m=4, k=8 = (k-1)/(m + k - 1) = 7/11 ≈ 63.6% — over half the schedule is bubble. Step time is dominated by max(stage_i) = 175 ms (stage 8), so steady-state pipeline rate = 1 / 175 ms regardless of how many other stages are 100 ms. Two changes are needed: (a) shrink the stage-8 imbalance by splitting the LM head across two ICI-connected chips (stage-8 compute drops to ~95 ms, matching the others) — this restores max(stage) ≈ 100 ms; (b) raise micro-batches to m=32 so bubble fraction drops to (8-1)/(32 + 8 - 1) = 7/39 ≈ 17.9%. Together, utilization climbs from ~36% to ~82% — within 10% of the 91% ideal asymptote.', 'Naive pipeline time for one global step at m=4: T = (m + k - 1) * max(stage) = (4 + 7) * 175 = 1925 ms. Useful work = m * sum(stage) / k = 4 * (7*100 + 175) / 8 = 437.5 ms. Utilization = 437.5 / 1925 ≈ 22.7%. After rebalance (max stage = 100 ms) and m=32: T = (32 + 7) * 100 = 3900 ms, useful work = 32 * 100 = 3200 ms, utilization = 82.0%.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3429.yaml', '34230afd9ceada98f7c5396b94fec73fd0826ae1de86fdfa2c3983ae75db9ec6', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3431', '3D Parallelism Sizing — Adam State + Activations on A100s', '3d-parallelism', 'cloud', 'L2', 'analyze', 'parallelism', 'analyze', 'training', 'published', 'A 70B-parameter transformer is trained on A100 80 GB GPUs (NVLink intra-node, IB inter-node). Each parameter under mixed-precision Adam costs 16 bytes of model state (FP16 weight + FP16 grad + FP32 master + FP32 m + FP32 v). Reserve 16 GB per GPU for activations + workspace. The team must choose TP, PP, and DP sizes that respect the per-GPU HBM budget. Decompose how each parallelism axis (DP, TP, PP) reduces (or fails to reduce) the per-GPU memory footprint.', 'Decompose how DP, TP, and PP each affect the per-GPU memory footprint for a 70B Adam-trained model on 80 GB A100s, and choose minimum (TP, PP) to fit.', 'Assuming DP alone reduces per-GPU memory. DP only divides the *batch*, not the model state — 64 DP ranks each still hold the full 1120 GB of state without TP/PP/ZeRO. Conversely, naive TP across nodes pays InfiniBand''s ~25 GB/s unidirectional bandwidth on every layer''s AllReduce and stalls; TP belongs inside the NVLink island.', 'DP replicates model state across ranks — it does *not* reduce per-GPU memory at all. TP shards weights, gradients, and (with ZeRO-1) part of the optimizer state along a tensor dimension; the full model state divides by TP. PP shards layers across stages; the full model state divides by PP. For 70B params * 16 bytes = 1120 GB of model state; per-GPU budget is 80 - 16 = 64 GB; minimum (TP * PP) ≥ 1120 / 64 = 17.5 → 18, rounded up to a topology-friendly TP=8 (within a node, on NVLink) and PP=4 (across nodes), giving TP*PP = 32, per-GPU model state = 35 GB, leaving 29 GB for activations and workspace. DP can then be added freely for throughput without affecting fit.', '70B params * 16 bytes (mixed-precision Adam) = 1120 GB total state. Per-GPU model budget: 80 - 16 (activations) = 64 GB. Required min(TP * PP) = ceil(1120 / 64) = 18. Choose TP=8 (NVLink-bound) + PP=4 (cross-node) → 32-way model split, per-GPU model = 35 GB, activation budget = 29 GB. DP=N multiplies global batch by N with zero per-GPU memory cost.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3431.yaml', '2f065e938c7e0c069dcc7c37f285affc9a715ec997e72233d2ffa80f5a016920', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3449', 'Inference Tail-Latency vs Training Throughput Contention on TPU v5e', 'scheduling-resource-management', 'cloud', 'L6+', 'mastery', 'parallelism', 'analyze', 'inference', 'published', 'A multi-tenant TPU v5e pod (each chip 16 GB HBM, 197 TFLOPS BF16, 1.6 TB/s HBM, ICI ~25 GB/s per axis) co-locates a critical inference service (p99 SLO 80 ms, 4 GB HBM, peak 60 TFLOPS) with a long-running data-parallel training job (8-chip slice, 12 GB HBM per chip, peak 130 TFLOPS per chip). Under load, training''s per-step ICI AllReduce monopolizes the inter-chip ring for ~9 ms windows, pushing inference p99 from 60 ms to 145 ms — a 1.8x SLO violation. Choose a single resource-management strategy that restores the inference SLO and quantify the cost to training throughput.', 'How would you eliminate the 9 ms ICI AllReduce tail that blows the inference SLO on a shared TPU v5e pod, and what does it cost the training job?', 'Applying generic CPU/GPU MIG/MPS partitioning logic to TPU v5e. v5e exposes ICI as a hard-partitioned mesh, so the fix is *physical* slice isolation, not time-slicing. Time-slicing a TPU under SPMD breaks the synchronous ring and produces *worse* tail latency than the contention it was meant to fix.', 'Bind the inference workload to a dedicated 1-chip slice with reserved ICI bandwidth (gang-scheduled at job start), and let the 8-chip training slice keep ring-AllReduce on its own sub-topology. This costs the training job one chip''s worth of compute (~12.5% throughput drop), but eliminates the tail-causing ring contention. As a complement, run training AllReduce in 8-MB chunks so that even brief preempting kernels can interleave with no more than ~1 ms of ICI dwell — keeps inference p99 under the 80 ms SLO. Avoid TPU-wide context-switch preemption: the SPMD execution model means any preempted shard stalls every other shard in the slice, so the 1 ms preemption granularity becomes 9 ms in practice.', 'Training 8-chip ring AllReduce per step: 2*(7/8) * 2 GB / 25 GB/s ≈ 140 ms wall clock, of which ~9 ms is the longest contiguous ICI window any one chip dominates. Inference path: 60 ms compute + 9 ms ICI stall = 69 ms baseline → spikes to 145 ms when stalls cluster. Reserving 1 dedicated chip for inference: training compute drops from 8 * 130 = 1040 TFLOPS to 7 * 130 = 910 TFLOPS (-12.5%), and inference p99 tail drops back to ~65 ms (no more ICI dwell from training). 8-MB chunked AllReduce: each chunk = 8 MB / 25 GB/s ≈ 0.32 ms, so any preempting inference kernel sees ≤ 1 ms ICI hold.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3449.yaml', '84daf3d9cbe9e3658eae9fcb451da104d525b9d96726792100b30d0d8a730489', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3927', '1F1B vs GPipe — What 1F1B Actually Saves', 'communication-computation-overlap', 'cloud', 'L4', 'fluency', 'parallelism', 'understand', 'both', 'published', 'Your 4-stage pipeline-parallel training of a 70B model on H100s uses 8 micro-batches per global step. A colleague claims that switching from GPipe to 1F1B (one-forward-one-backward) will reduce the pipeline bubble. Evaluate the claim quantitatively and identify what 1F1B does in fact change.', 'For 4 stages and 8 micro-batches, what is the bubble fraction under GPipe versus 1F1B, and what does 1F1B actually save if not bubble time?', 'Claiming 1F1B reduces the bubble fraction. It does not: both schedules share (k-1)/(m + k - 1). The improvement is in peak activation memory (O(m) → O(k)), which is what enables larger micro-batch counts and therefore *indirectly* shrinks the bubble fraction by allowing larger m.', 'GPipe and 1F1B share the *same* steady-state bubble fraction: (k-1)/(m + k - 1). For k = 4 and m = 8 that is 3/11 ≈ 27.3% under both schedules. 1F1B''s real win is peak activation memory: in GPipe, all m micro-batches'' forward activations are kept resident until the global flush, giving O(m) activation memory. In 1F1B, after the warmup (k-1 forwards), each forward is followed by a backward that releases that micro-batch''s activations, so peak activation memory is O(k). At k=4, m=8 this is a 2x reduction in stored activations per stage, which directly determines whether the 70B model fits in HBM.', 'k = 4, m = 8. GPipe bubble fraction = 1F1B bubble fraction = (4-1) / (8 + 4 - 1) = 3/11 ≈ 27.3%. Activation memory: GPipe stores 8 micro-batches'' forward activations at peak; 1F1B stores at most k = 4. If each micro-batch''s per-stage activation is ~5 GB, GPipe peak is 40 GB versus 1F1B''s 20 GB — only 1F1B leaves headroom on an 80 GB H100 for weights, gradients, and the optimizer shard.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3927.yaml', 'bcc6db44a674c1f90a8e66d72c45e6197b04988dab7e2aa8c639451aea1508e0', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3930', 'Overlap Efficiency Degradation at Scale: 8 GPUs vs 256 GPUs', 'communication-computation-overlap', 'cloud', 'L5', 'diagnosis', 'parallelism', 'analyze', 'both', 'published', 'Your DDP training achieves 92% overlap efficiency at 8 H100 GPUs (single node, NVLink) but only 68% at 256 H100 GPUs (32 nodes, InfiniBand). AllReduce time grows faster than expected. Diagnose why overlap degrades at scale.', 'Why does AllReduce overlap efficiency fall from 92% at 8 H100s to 68% at 256 H100s, and how would you fix it?', 'Assuming AllReduce time scales linearly with node count. Ring AllReduce time is 2(n-1)/n x M/B (nearly constant for large n), but in practice, cross-node AllReduce has much higher latency than intra-node NVLink AllReduce.', 'Three factors degrade overlap at 256 GPUs: (1) AllReduce latency increases: intra-node NVLink ring at 900 GB/s vs inter-node IB at 50 GB/s per link. For 5.2GB gradients: NVLink AllReduce ~6ms, IB AllReduce ~104ms. The 104ms AllReduce exceeds the backward pass time, making overlap impossible. (2) Network congestion: 32 nodes doing simultaneous AllReduce creates IB fabric contention, adding 10-30% overhead. (3) Bucket synchronization: 256 processes must synchronize bucket readiness, adding coordination latency. Fix: use hierarchical AllReduce (intra-node reduce first via NVLink, then inter-node AllReduce of reduced results). This cuts inter-node traffic by 8x.', 'Hierarchical AR: Step 1: 8-GPU reduce-scatter on NVLink, 5.2GB / 8 = 650MB per GPU shard. Step 2: inter-node AllReduce of the per-rank 650MB shard across N=32 nodes — bus traffic = 2*(31/32) * 650 MB ≈ 1.26 GB, at 50 GB/s = 25.2 ms (the 2x AllReduce factor was missing in earlier drafts). Step 3: intra-node all-gather, ~1ms. Total: ~26 ms vs flat AllReduce 104 ms. Overlap at 26 ms is feasible against a 200ms backward pass with bucketed pipelining.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3930.yaml', '237167cdc99c88c91c363760abe434b894bab64b62f75eeeff982e02546b3ae6', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-3931', 'Tensor Parallelism AllReduce Overlap with Feedforward Computation', 'communication-computation-overlap', 'cloud', 'L4', 'fluency', 'parallelism', 'understand', 'both', 'published', 'In tensor-parallel training of a 70B LLM across 8 H100 GPUs (NVLink), each transformer layer requires two AllReduce operations: one after the attention block and one after the MLP block. These AllReduces are on the critical path. Can they be overlapped with computation?', 'Can they be overlapped with computation?', 'Assuming tensor parallelism AllReduces can be overlapped like DDP gradient AllReduces. In tensor parallelism, the AllReduce output is the input to the next computation — there is a strict data dependency.', 'Standard tensor parallelism AllReduces cannot be overlapped because each produces a partial sum that is needed before the next layer starts. However, two techniques partially address this: (1) Async ReduceScatter + AllGather decomposition: split AllReduce into ReduceScatter (output partial results while computing) + AllGather (reconstruct while starting next layer''s computation). The AllGather can partially overlap with the next layer''s input processing. (2) Sequence parallelism: overlap the sequence dimension''s AllGather with computation by processing received chunks as they arrive. Megatron-LM uses this to overlap 30-40% of communication.', '70B model, 8-way TP, 96 layers, batch=4 micro-batches per TP rank, hidden=8192, seq=2048, BF16. Per-AllReduce activation tensor = batch * seq * hidden * 2 bytes = 4 * 2048 * 8192 * 2 ≈ 134 MB. Ring AllReduce bus traffic per layer = 2*(7/8) * 134 MB ≈ 235 MB. NVLink unidirectional 450 GB/s: 235 MB / 450 GB/s ≈ 0.52 ms per AllReduce. 192 AllReduces (2 per layer) * 0.52 ms ≈ 100 ms per step from TP comm alone. Compute per layer ≈ 5 ms (480 ms total) — TP comm is ~21% of compute. Sequence parallelism + async ReduceScatter+AllGather decomposition typically recovers 30-40% of this, leaving ~60-70 ms exposed.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-3931.yaml', 'f117d93d984865b2327e51ba13d4238d9792a5889c411125a82b2951412c92e3', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-4047', 'Gradient Synchronization for ZeRO Stage 3', 'gradient-synchronization', 'cloud', 'L5', 'design', 'parallelism', 'create', 'training', 'published', 'ZeRO Stage 3 partitions model parameters, gradients, and optimizer states across GPUs. Unlike standard data parallelism where each GPU holds a full copy, each GPU only holds 1/N of everything. This means forward/backward passes require all-gather of parameters before each layer and reduce-scatter of gradients after. Design the communication schedule for a 64-MI300X cluster training a 30B parameter model with 60 Transformer layers.', 'What is the ZeRO-3 per-layer communication schedule and cost for a 64-MI300X, 30B-parameter, 60-layer training run?', 'Applying the 2*(N-1)/N AllReduce factor to AllGather and ReduceScatter. Each of those two collectives moves (N-1)/N * size, and AllReduce = ReduceScatter + AllGather, which is where its 2*(N-1)/N comes from. Treating them as if each cost 2*(N-1)/N independently double-counts the traffic and gives ZeRO-3 a 6x rather than 3x bus-traffic ratio over flat AllReduce.', 'Model: 30B params = 60GB FP16. Per GPU (64 GPUs): 60GB/64 = 937.5MB of parameters, gradients, and optimizer states (vs the 60 GB full copy). Per-layer communication: Forward AllGather = (N-1)/N * 1 GB per layer (60 all-gathers total). Backward AllGather = (N-1)/N * 1 GB per layer (parameters needed again, 60 more). Gradient ReduceScatter at end of backward = (N-1)/N * 1 GB per layer (60 reduce-scatters). Note: AllGather and ReduceScatter each move (N-1)/N * size of bus traffic — *not* 2*(N-1)/N — that 2x factor is for AllReduce only. Total bus traffic per iteration: 3 × 60 × 63/64 × 1 GB ≈ 177.2 GB. At 50 GB/s un-pipelined: ~3.5 s without overlap. With prefetching: each AllGather of 1 GB takes 63/64 / 50 = 19.7 ms; layer compute ~5 ms, so communication is ~4x slower than per-layer compute and prefetching can overlap most of it. Using all 8 NICs on MI300X (8 × 400 Gbps ≈ 400 GB/s aggregate): AllGather drops to ~2.5 ms ≈ compute, enabling near-perfect overlap.', 'Memory savings: 60 GB (full copy) → 937.5 MB (ZeRO-3) per GPU = 64x reduction. Per-layer bus traffic: AllGather (fwd) + AllGather (bwd) + ReduceScatter = 3 * (N-1)/N * 1 GB ≈ 2.95 GB. Across 60 layers: ~177.2 GB per iteration vs ~62.0 GB for a flat AllReduce in standard DP (2*(63/64)*60 GB) — roughly 2.85x more bus traffic, hidden by per-layer prefetching when NIC bandwidth ≥ compute intensity per layer.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-4047.yaml', '1e7ca218f97802b65bf6d8827ca6330e454d410b64dce78a0e5523e2820da0e0', NULL);
INSERT OR REPLACE INTO questions (id, title, topic, track, level, zone, competency_area, bloom_level, phase, status, scenario, question, common_mistake, realistic_solution, napkin_math, provenance, created_at, last_modified, human_review_status, human_review_by, human_review_date, file_path, content_hash, authors_json) VALUES ('cloud-4087', 'TP Layout Under an Asymmetric Bandwidth Budget', 'model-tensor-parallelism', 'cloud', 'L3', 'fluency', 'parallelism', 'understand', 'training', 'published', 'An 8B-parameter dense block runs on a 4-GPU mini-pod where 2 GPUs share a fast NVLink lane (450 GB/s unidirectional) and the other 2 GPUs are connected to that pair only over PCIe Gen4 (~25 GB/s unidirectional). The block has hidden dim H_in = H_out = 8192 and is currently column-parallel, ending in an AllGather across all 4 ranks. Decide whether to keep column-parallel + AllGather, or switch to row-parallel + AllReduce, given the asymmetric fabric. Quantify the collective time under each layout and identify the binding link.', 'On 4 GPUs with a 2x NVLink pair + 2x PCIe pair, should the [8192, 8192] linear block use column-parallel + AllGather or row-parallel + AllReduce, and why?', 'Choosing layout by FLOPs symmetry alone. Both layouts have identical compute (16.78M params per shard), so the answer must come from collective cost — and the collective cost is asymmetric: AllReduce moves twice the bytes of AllGather across the same ring. The other common error is naming NVLink (450 GB/s) as the binding link when the PCIe edge (25 GB/s) is 18x slower.', 'Column-parallel: each rank holds [8192, 2048] of W and produces a [batch, 2048] output partition. The end-of-block AllGather across 4 ranks moves 3/4 * 4 * batch * 2048 * 2 bytes = 3 * batch * 4096 bytes through the slowest link. For batch=2048 that is ~24 MB across the slowest PCIe edge → ~0.96 ms. Row-parallel: each rank holds [2048, 8192] of W; input must first be split [batch, 2048], and the output is a partial sum requiring an AllReduce of [batch, 8192]. AllReduce moves 2*(N-1)/N = 1.5x the [batch, 8192] tensor (32 MB at batch=2048) → 48 MB across the slowest link → ~1.92 ms. Column-parallel + AllGather wins by ~2x because AllGather moves N-1/N of the small sharded tensor while AllReduce moves 2*(N-1)/N of the *full* tensor. The PCIe leg is the binding link in both cases — keep TP inside the NVLink pair when possible.', 'H_in = H_out = 8192, TP=4, batch=2048, BF16. Column-parallel + AllGather across 4 ranks: bus traffic = 3/4 * 4 * 2048 * 2048 * 2 = 24 MB through 25 GB/s PCIe → 0.96 ms. Row-parallel + AllReduce: bus traffic = 2*(3/4) * 2048 * 8192 * 2 = 48 MB → 1.92 ms. Per-shard weights either layout: 8192 * 2048 = 16.78 M params × 2 B = 33.6 MB.', 'imported', NULL, NULL, 'not-reviewed', NULL, NULL, 'interviews/vault/questions/cloud/cloud-4087.yaml', '07923f85f2ed36b7c0f19e94e19ce9f5c3891acfb10a53b55835376ccb3c8deb', NULL);
